payload.text:
To expand the layout options for manga generation, I will update the `types`, `service`, and `App` component.

Here are the changes:
1.  **`types.ts`**: Update `MangaGenerationParams` to include 'grid', '4-koma', and 'dynamic' in the `layoutType`.
2.  **`services/geminiService.ts`**: Add a prompt mapping to translate the new layout types into descriptive instructions for the model (e.g., "classic 6-panel grid" or "dynamic action layout").
3.  **`App.tsx`**: Import new icons and update the Layout selector UI to a 2x3 grid of options.

# Updated files:

## types.ts

Expanded the `layoutType` definition.

```typescript
export interface MangaGenerationParams {
  mode: 'manga' | 'edit';
  model: string; // 'gemini-3-pro-image-preview' | 'gemini-2.5-flash-image'
  userImage: string; // Base64
  referenceImage?: string; // Base64

  // Manga Mode Specifics
  styleName?: string;
  dialogue?: string;
  layoutType?: 'single' | 'double' | 'strip' | 'grid' | '4-koma' | 'dynamic';

  // Edit Mode Specifics
  editPrompt?: string;
}

export interface GenerationResult {
  imageUrl?: string;
  text?: string;
}

export enum GenerationStatus {
  IDLE = 'IDLE',
  GENERATING = 'GENERATING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR',
}
```

## services/geminiService.ts

Updated the prompt construction to handle the new layout types.

```typescript
import { GoogleGenAI } from "@google/genai";
import { MangaGenerationParams, GenerationResult } from "../types";

/**
 * Helper to convert base64 string to the format expected by Gemini (raw base64 without prefix)
 */
const cleanBase64 = (base64Data: string): string => {
  return base64Data.split(',')[1] || base64Data;
};

/**
 * Generates a manga page or edits an image using the selected Gemini model
 */
export const generateMangaPage = async (params: MangaGenerationParams): Promise<GenerationResult> => {
  try {
    // Initialize the Gemini client inside the function to ensure we grab the latest API key
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const parts: any[] = [];

    // 1. Add the User Image (The Subject / Source)
    parts.push({
      inlineData: {
        mimeType: 'image/jpeg', // Assuming JPEG/PNG from input
        data: cleanBase64(params.userImage),
      },
    });

    // 2. Add Reference Image if provided
    if (params.referenceImage) {
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: cleanBase64(params.referenceImage),
        },
      });
    }

    // 3. Construct the text prompt based on mode
    let prompt = '';

    if (params.mode === 'edit') {
      if (!params.editPrompt) {
        throw new Error("Please provide instructions for the image edit.");
      }

      prompt = `Act as a professional photo editor.

      User Request: "${params.editPrompt}"

      Instructions:
      - The first image is the SOURCE.
      ${params.referenceImage ? '- The second image is a STYLE REFERENCE.' : ''}
      - Modify the source image according to the user request with photorealistic precision.
      - Maintain high resolution and details.
      `;
    } else {
      // Default: Manga Mode
      const layoutPrompts: Record<string, string> = {
        'single': 'single full-page composition',
        'double': 'double-page spread composition',
        'strip': 'vertical webtoon-style strip',
        'grid': 'classic 6-panel grid layout',
        '4-koma': '4-panel yonkoma vertical comic strip',
        'dynamic': 'dynamic action layout with diagonal cuts, varying panel sizes, and breaking borders'
      };

      const layoutInstruction = layoutPrompts[params.layoutType || 'single'] || 'single page composition';

      prompt = `You are a professional manga artist. Create a high-fidelity manga illustration.

      Instructions:
      1. Subject: The first image provided is the MAIN CHARACTER.
      ${params.referenceImage ? '2. Style: The second image is the ART STYLE REFERENCE. Mimic its line weight, shading technique, and tone exactly.' : ''}
      3. Aesthetic: ${params.styleName || 'Seinen Manga (High Detail)'}.
      4. Layout: Create a ${layoutInstruction}.
      ${params.dialogue ? `5. Text: Include the dialogue "${params.dialogue}" in a natural speech bubble.` : ''}

      Output Requirements:
      - Crisp, professional ink lines.
      - High dynamic range in black and white values.
      - If the user asks for color, provide it, otherwise default to black and white manga style.
      `;
    }

    parts.push({ text: prompt });

    // 4. Configure based on model
    const modelName = params.model;
    let config = {};

    // Only Pro model supports detailed imageConfig (like size) and tools (like search)
    // Flash Image (Nano Banana) is more limited
    if (modelName === 'gemini-3-pro-image-preview') {
      config = {
        imageConfig: {
          aspectRatio: params.layoutType === 'double' ? "16:9" : params.layoutType === 'strip' ? "9:16" : "1:1",
          imageSize: "1K"
        }
      };
    }

    // 5. Call the model
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts },
      config: config
    });

    // 6. Parse the response
    let generatedImageUrl: string | undefined;
    let generatedText: string | undefined;

    if (response.candidates && response.candidates[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          generatedImageUrl = `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`;
        } else if (part.text) {
          generatedText = part.text;
        }
      }
    }

    if (!generatedImageUrl) {
      throw new Error("No image was generated. The model might have refused the request due to safety guidelines.");
    }

    return {
      imageUrl: generatedImageUrl,
      text: generatedText
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);

    // Enhanced Error Handling
    let errorMessage = "An unexpected error occurred. Please try again.";
    const message = (error.message || "").toLowerCase();
    const errorStr = error.toString().toLowerCase();

    if (message.includes('400') || errorStr.includes('400')) {
      errorMessage = "Bad Request: The image might be too large or in an unsupported format.";
    } else if (message.includes('401') || errorStr.includes('401')) {
      errorMessage = "Authorization Error: Please check your API Key.";
    } else if (message.includes('403') || errorStr.includes('403')) {
      errorMessage = "Permission Denied: Your API key doesn't have access to this model.";
    } else if (message.includes('429') || errorStr.includes('429')) {
      errorMessage = "Quota Exceeded: You're generating too fast. Take a breather.";
    } else if (message.includes('500') || errorStr.includes('500')) {
      errorMessage = "Server Error: The Gemini service is temporarily unavailable.";
    } else if (message.includes('safety') || message.includes('blocked')) {
      errorMessage = "Safety Block: The request was flagged by safety filters.";
    }

    throw new Error(errorMessage);
  }
};
```

## App.tsx

Added layout icons and updated the layout selector.

```tsx
import React, { useState, useEffect } from 'react';
import { ImageUploader } from './components/ImageUploader';
import { LoadingOverlay } from './components/LoadingOverlay';
import { Header } from './components/Header';
import { generateMangaPage } from './services/geminiService';
import { GenerationStatus } from './types';
import { 
  Download, RefreshCw, Wand2, PenTool, Sparkles, 
  Layout as LayoutIcon, MessageSquare, ChevronRight, Key,
  Zap, Gem, ArrowRight,
  Grid, BookOpen, StretchVertical, AlignJustify
} from 'lucide-react';

// Add types for window.aistudio
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    aistudio?: AIStudio;
  }
}

function App() {
  // -- App State --
  const [selectedModel, setSelectedModel] = useState<string | null>(null);

  // -- API Key State --
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [isCheckingKey, setIsCheckingKey] = useState(false); // Start false, check only if needed

  // -- Content State --
  const [mode, setMode] = useState<'manga' | 'edit'>('manga');
  const [userImage, setUserImage] = useState<string | null>(null);
  const [refImage, setRefImage] = useState<string | null>(null);

  // Manga Mode State
  const [styleName, setStyleName] = useState('');
  const [dialogue, setDialogue] = useState('');
  const [layoutType, setLayoutType] = useState<'single' | 'double' | 'strip' | 'grid' | '4-koma' | 'dynamic'>('single');

  // Edit Mode State
  const [editPrompt, setEditPrompt] = useState('');

  // Generation State
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // -- Effects --

  // Check key ONLY if Pro model is selected
  useEffect(() => {
    if (selectedModel === 'gemini-3-pro-image-preview') {
      checkApiKey();
    } else if (selectedModel === 'gemini-2.5-flash-image') {
      // For standard model, we assume environment key is enough, or valid
      setHasApiKey(true); 
    }
  }, [selectedModel]);

  const checkApiKey = async () => {
    setIsCheckingKey(true);
    try {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(hasKey);
      }
    } catch (e) {
      console.error("Error checking API key status", e);
    } finally {
      setIsCheckingKey(false);
    }
  };

  const handleSelectKey = async () => {
    try {
      if (window.aistudio) {
        await window.aistudio.openSelectKey();
        setHasApiKey(true);
      }
    } catch (e) {
      console.error("Error selecting key", e);
    }
  };

  // -- Handlers --
  const handleGenerate = async () => {
    // Re-verify key for Pro model
    if (selectedModel === 'gemini-3-pro-image-preview' && !hasApiKey) {
      handleSelectKey();
      return;
    }

    if (!userImage) {
      setErrorMsg("Please upload a source image.");
      return;
    }

    if (mode === 'edit' && !editPrompt.trim()) {
      setErrorMsg("Please describe the edits you want to make.");
      return;
    }

    setStatus(GenerationStatus.GENERATING);
    setErrorMsg(null);
    setResultImage(null);

    try {
      const result = await generateMangaPage({
        mode,
        model: selectedModel!, // Passed here
        userImage,
        referenceImage: refImage || undefined,
        styleName: styleName || "Manga",
        dialogue: dialogue || undefined,
        layoutType,
        editPrompt: editPrompt || undefined
      });

      if (result.imageUrl) {
        setResultImage(result.imageUrl);
        setStatus(GenerationStatus.SUCCESS);
      }
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "Generation failed.");
      setStatus(GenerationStatus.ERROR);

      if (err.message.includes("API Key") && selectedModel === 'gemini-3-pro-image-preview') {
        setHasApiKey(false);
      }
    }
  };

  const handleDownload = () => {
    if (resultImage) {
      const link = document.createElement('a');
      link.href = resultImage;
      link.download = `nano-manga-${Date.now()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  // -- Render 1: Model Selection Screen --
  if (!selectedModel) {
    return (
      <div className="h-screen w-full bg-gray-900 flex flex-col items-center justify-center p-6 relative overflow-hidden">
        {/* Background Accents */}
        <div className="absolute top-[-20%] right-[-10%] w-[600px] h-[600px] bg-indigo-600/20 rounded-full blur-[120px] animate-pulse" />
        <div className="absolute bottom-[-20%] left-[-10%] w-[600px] h-[600px] bg-yellow-500/10 rounded-full blur-[120px]" />

        <div className="text-center mb-12 z-10 animate-fade-in">
          <h1 className="text-5xl font-bold text-white font-display mb-4 tracking-tight">
            Choose Your Engine
          </h1>
          <p className="text-gray-400 text-lg max-w-xl mx-auto">
            Select the AI model that best fits your creative needs.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-5xl w-full z-10">

          {/* Option 1: Nano Banana Pro */}
          <button 
            onClick={() => setSelectedModel('gemini-3-pro-image-preview')}
            className="group relative bg-gray-800/50 backdrop-blur-xl border border-gray-700 hover:border-indigo-500/50 rounded-3xl p-8 text-left transition-all duration-300 hover:shadow-2xl hover:shadow-indigo-900/20 hover:-translate-y-1"
          >
            <div className="absolute inset-0 bg-gradient-to-br from-indigo-600/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity rounded-3xl" />

            <div className="flex justify-between items-start mb-6">
              <div className="p-4 rounded-2xl bg-indigo-600/20 text-indigo-400 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                <Gem className="w-8 h-8" />
              </div>
              <div className="px-3 py-1 rounded-full bg-indigo-900/50 border border-indigo-700/50 text-indigo-300 text-xs font-bold tracking-wider">
                RECOMMENDED
              </div>
            </div>

            <h2 className="text-2xl font-bold text-white mb-3 group-hover:text-indigo-300 transition-colors">Nano Banana Pro</h2>
            <p className="text-gray-400 mb-6 leading-relaxed">
              Powered by <strong>Gemini 3 Pro Image</strong>. Best for high-fidelity artwork, complex scenes, and professional quality output.
            </p>

            <div className="flex items-center text-indigo-400 text-sm font-semibold group-hover:translate-x-1 transition-transform">
              Select Engine <ArrowRight className="w-4 h-4 ml-2" />
            </div>
          </button>

          {/* Option 2: Nano Banana */}
          <button 
            onClick={() => setSelectedModel('gemini-2.5-flash-image')}
            className="group relative bg-gray-800/50 backdrop-blur-xl border border-gray-700 hover:border-yellow-500/50 rounded-3xl p-8 text-left transition-all duration-300 hover:shadow-2xl hover:shadow-yellow-900/20 hover:-translate-y-1"
          >
             <div className="absolute inset-0 bg-gradient-to-br from-yellow-600/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity rounded-3xl" />

            <div className="flex justify-between items-start mb-6">
              <div className="p-4 rounded-2xl bg-yellow-600/20 text-yellow-400 group-hover:bg-yellow-600 group-hover:text-white transition-colors">
                <Zap className="w-8 h-8" />
              </div>
              <div className="px-3 py-1 rounded-full bg-gray-700/50 border border-gray-600 text-gray-400 text-xs font-bold tracking-wider">
                FAST
              </div>
            </div>

            <h2 className="text-2xl font-bold text-white mb-3 group-hover:text-yellow-300 transition-colors">Nano Banana</h2>
            <p className="text-gray-400 mb-6 leading-relaxed">
              Powered by <strong>Gemini 2.5 Flash Image</strong>. Ideal for quick sketches, edits, and rapid prototyping.
            </p>

            <div className="flex items-center text-yellow-400 text-sm font-semibold group-hover:translate-x-1 transition-transform">
              Select Engine <ArrowRight className="w-4 h-4 ml-2" />
            </div>
          </button>
        </div>
      </div>
    );
  }

  // -- Render 2: API Key Auth (Pro Only) --
  if (selectedModel === 'gemini-3-pro-image-preview' && !isCheckingKey && !hasApiKey) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-900 text-white p-4 animate-fade-in">
        <div className="max-w-md w-full bg-gray-800 p-8 rounded-2xl shadow-2xl border border-gray-700 text-center relative overflow-hidden">
          <button 
            onClick={() => setSelectedModel(null)}
            className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors text-xs font-medium"
          >
            ← Back
          </button>

          <div className="w-16 h-16 bg-indigo-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-lg shadow-indigo-500/30">
            <Key className="w-8 h-8 text-white" />
          </div>
          <h2 className="text-2xl font-bold mb-2 font-display">Authentication Required</h2>
          <p className="text-gray-400 mb-8 text-sm leading-relaxed">
            You selected the <strong>Pro</strong> engine. This requires a paid API key.
          </p>
          <button 
            onClick={handleSelectKey}
            className="w-full py-3.5 px-6 bg-indigo-500 hover:bg-indigo-400 text-white font-semibold rounded-xl transition-all flex items-center justify-center gap-2"
          >
            Select API Key
            <ChevronRight className="w-4 h-4" />
          </button>
          <div className="mt-4 text-xs text-gray-500">
            <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline hover:text-gray-300">Billing Information</a>
          </div>
        </div>
      </div>
    );
  }

  // -- Render 3: Main App --
  return (
    <div className="h-screen flex flex-col bg-gray-50 overflow-hidden animate-fade-in">
      <LoadingOverlay isVisible={status === GenerationStatus.GENERATING} message={mode === 'manga' ? "Inking Pages..." : "Processing Edits..."} />
      <Header modelName={selectedModel} />

      <main className="flex-1 flex overflow-hidden">

        {/* --- Left Sidebar: Controls --- */}
        <aside className="w-full max-w-[400px] flex-shrink-0 bg-white border-r border-gray-200 flex flex-col overflow-hidden z-10 shadow-xl shadow-gray-200/50">

          {/* Mode Switcher */}
          <div className="p-4 border-b border-gray-100">
             {/* Back to Model Selection */}
             <button 
                onClick={() => {
                  setSelectedModel(null);
                  setHasApiKey(false);
                  setResultImage(null);
                  setUserImage(null);
                }}
                className="w-full mb-4 text-xs font-medium text-gray-400 hover:text-gray-700 flex items-center justify-center gap-1 transition-colors"
             >
                <span>Switch Engine</span>
             </button>

            <div className="grid grid-cols-2 gap-1 p-1 bg-gray-100/80 rounded-xl">
              <button
                onClick={() => setMode('manga')}
                className={`flex items-center justify-center gap-2 py-2.5 rounded-lg text-sm font-semibold transition-all duration-200
                  ${mode === 'manga' 
                    ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-black/5' 
                    : 'text-gray-500 hover:text-gray-700'
                  }
                `}
              >
                <PenTool className="w-4 h-4" />
                Manga
              </button>
              <button
                onClick={() => setMode('edit')}
                className={`flex items-center justify-center gap-2 py-2.5 rounded-lg text-sm font-semibold transition-all duration-200
                  ${mode === 'edit' 
                    ? 'bg-white text-purple-600 shadow-sm ring-1 ring-black/5' 
                    : 'text-gray-500 hover:text-gray-700'
                  }
                `}
              >
                <Sparkles className="w-4 h-4" />
                Edit
              </button>
            </div>
          </div>

          {/* Scrollable Inputs */}
          <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8">

            {/* Image Inputs */}
            <section className="space-y-4 animate-fade-in" style={{ animationDelay: '0.1s' }}>
              <ImageUploader 
                label="Source Image" 
                subLabel="Required"
                image={userImage} 
                onImageChange={setUserImage}
              />
              <ImageUploader 
                label="Style Reference" 
                subLabel="Optional"
                image={refImage} 
                onImageChange={setRefImage}
                compact
              />
            </section>

            {/* Contextual Inputs */}
            <section className="animate-fade-in" style={{ animationDelay: '0.2s' }}>
              {mode === 'manga' ? (
                <div className="space-y-6">
                  {/* Style Name */}
                  <div>
                    <label className="text-xs font-bold text-gray-900 uppercase tracking-wider mb-2 block">
                      Art Style
                    </label>
                    <div className="relative group">
                      <input
                        type="text"
                        placeholder="e.g. Cyberpunk, Vintage Shojo, Sketch"
                        value={styleName}
                        onChange={(e) => setStyleName(e.target.value)}
                        className="w-full pl-10 pr-4 py-3 rounded-xl bg-gray-50 border-transparent focus:bg-white focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 transition-all text-sm outline-none"
                      />
                      <Wand2 className="absolute left-3 top-3 w-4 h-4 text-gray-400 group-focus-within:text-indigo-500 transition-colors" />
                    </div>
                  </div>

                  {/* Layout Type */}
                  <div>
                    <label className="text-xs font-bold text-gray-900 uppercase tracking-wider mb-2 block">
                      Layout
                    </label>
                    <div className="grid grid-cols-3 gap-2">
                      {[
                        { id: 'single', label: 'Single', icon: LayoutIcon },
                        { id: 'double', label: 'Spread', icon: BookOpen },
                        { id: 'strip', label: 'Webtoon', icon: StretchVertical },
                        { id: 'grid', label: 'Grid', icon: Grid },
                        { id: '4-koma', label: '4-Koma', icon: AlignJustify },
                        { id: 'dynamic', label: 'Dynamic', icon: Zap },
                      ].map((item) => (
                        <button
                          key={item.id}
                          onClick={() => setLayoutType(item.id as any)}
                          className={`
                            flex flex-col items-center justify-center p-2 rounded-xl border text-[10px] font-bold uppercase tracking-wide transition-all min-h-[60px]
                            ${layoutType === item.id 
                              ? 'border-indigo-600 bg-indigo-50 text-indigo-700' 
                              : 'border-gray-200 text-gray-500 hover:bg-gray-50'
                            }
                          `}
                        >
                          <item.icon className="w-4 h-4 mb-1" />
                          {item.label}
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Dialogue */}
                  <div>
                    <label className="text-xs font-bold text-gray-900 uppercase tracking-wider mb-2 block">
                      Dialogue
                    </label>
                    <div className="relative">
                      <textarea
                        rows={3}
                        placeholder="Add text for speech bubbles..."
                        value={dialogue}
                        onChange={(e) => setDialogue(e.target.value)}
                        className="w-full p-3 rounded-xl bg-gray-50 border-transparent focus:bg-white focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 transition-all text-sm outline-none resize-none"
                      />
                      <MessageSquare className="absolute right-3 bottom-3 w-4 h-4 text-gray-300" />
                    </div>
                  </div>
                </div>
              ) : (
                // Edit Mode Inputs
                <div className="space-y-4">
                  <label className="text-xs font-bold text-gray-900 uppercase tracking-wider mb-2 block">
                    Magic Instructions
                  </label>
                  <textarea
                    rows={6}
                    placeholder="Describe your changes in detail...&#10;e.g. 'Make it look like a oil painting', 'Remove the person on the left', 'Add neon lights'"
                    value={editPrompt}
                    onChange={(e) => setEditPrompt(e.target.value)}
                    className="w-full p-4 rounded-xl bg-purple-50 border-transparent focus:bg-white focus:border-purple-500 focus:ring-2 focus:ring-purple-200 transition-all text-sm outline-none resize-none"
                  />
                </div>
              )}
            </section>
          </div>

          {/* Footer Action */}
          <div className="p-6 border-t border-gray-100 bg-white">
            {errorMsg && (
              <div className="mb-4 p-3 rounded-lg bg-red-50 border border-red-100 text-xs text-red-600">
                {errorMsg}
              </div>
            )}
            <button
              onClick={handleGenerate}
              disabled={!userImage || status === GenerationStatus.GENERATING}
              className={`
                w-full py-4 rounded-xl flex items-center justify-center gap-2 font-bold text-white shadow-lg shadow-indigo-200 transform active:scale-[0.98] transition-all
                ${!userImage || status === GenerationStatus.GENERATING
                  ? 'bg-gray-300 cursor-not-allowed shadow-none' 
                  : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500'
                }
              `}
            >
              {status === GenerationStatus.GENERATING ? (
                <span className="animate-pulse">Generative Process...</span>
              ) : (
                <>
                  <Wand2 className="w-5 h-5" />
                  <span>{mode === 'manga' ? 'Generate Manga' : 'Apply Edits'}</span>
                </>
              )}
            </button>
          </div>
        </aside>

        {/* --- Right Area: Canvas / Preview --- */}
        <section className="flex-1 bg-[#0f172a] relative flex flex-col overflow-hidden">

          {/* Canvas Toolbar */}
          <div className="absolute top-6 right-6 z-20 flex gap-2">
            {resultImage && (
              <>
                <button 
                  onClick={() => setResultImage(null)}
                  className="p-3 bg-gray-800/80 backdrop-blur-md hover:bg-gray-700 text-white rounded-full shadow-lg transition-all"
                  title="Clear Canvas"
                >
                  <RefreshCw className="w-4 h-4" />
                </button>
                <button 
                  onClick={handleDownload}
