            className="group relative bg-gray-800/50 backdrop-blur-xl border border-gray-700 hover:border-yellow-500/50 rounded-3xl p-6 md:p-8 text-left transition-all duration-300 hover:shadow-2xl hover:shadow-yellow-900/20 hover:-translate-y-1 flex flex-col"
          >
             <div className="absolute inset-0 bg-gradient-to-br from-yellow-600/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity rounded-3xl" />

            <div className="flex justify-between items-start mb-6">
              <div className="p-4 rounded-2xl bg-yellow-600/20 text-yellow-400 group-hover:bg-yellow-600 group-hover:text-white transition-colors">
                <Zap className="w-8 h-8" />
              </div>
              <div className="px-3 py-1 rounded-full bg-gray-700/50 border border-gray-600 text-gray-400 text-xs font-bold tracking-wider">
                FAST
              </div>
            </div>

            <h2 className="text-2xl font-bold text-white mb-3 group-hover:text-yellow-300 transition-colors">Nano Banana</h2>
            <p className="text-gray-400 mb-4 leading-relaxed text-sm md:text-base flex-grow">
              Powered by <strong>Gemini 2.5 Flash Image</strong>. Ideal for fast edits.
            </p>

            <div className="mb-6 p-3 rounded-xl bg-yellow-900/20 border border-yellow-500/20 text-yellow-200/80 text-xs leading-relaxed">
               Supports a <strong>limited number of subjects (max 3 images)</strong> and specific data is less detailed than Pro.
            </div>

            <div className="flex items-center text-yellow-400 text-sm font-semibold group-hover:translate-x-1 transition-transform mt-auto">
              Select Engine <ArrowRight className="w-4 h-4 ml-2" />
            </div>
          </button>
        </div>
      </div>
    );
  }

  // -- Render 2: API Key Auth (Pro Only) --
  if (selectedModel === 'gemini-3-pro-image-preview' && !isCheckingKey && !hasApiKey) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-900 text-white p-4 animate-fade-in">
        <div className="max-w-md w-full bg-gray-800 p-8 rounded-2xl shadow-2xl border border-gray-700 text-center relative overflow-hidden">
          <button 
            onClick={() => setSelectedModel(null)}
            className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors text-xs font-medium"
          >
            ← Back
          </button>

          <div className="w-16 h-16 bg-indigo-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-lg shadow-indigo-500/30">
            <Key className="w-8 h-8 text-white" />
          </div>
          <h2 className="text-2xl font-bold mb-2 font-display">Authentication Required</h2>
          <p className="text-gray-400 mb-8 text-sm leading-relaxed">
            You selected the <strong>Pro</strong> engine. This requires a paid API key.
          </p>
          <button 
            onClick={handleSelectKey}
            className="w-full py-3.5 px-6 bg-indigo-500 hover:bg-indigo-400 text-white font-semibold rounded-xl transition-all flex items-center justify-center gap-2"
          >
            Select API Key
            <ChevronRight className="w-4 h-4" />
          </button>
          <div className="mt-4 text-xs text-gray-500">
            <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline hover:text-gray-300">Billing Information</a>
          </div>
        </div>
      </div>
    );
  }

  // -- Render 3: Main App --
  const isGenerating = status === GenerationStatus.GENERATING;

  return (
    <div className="h-screen flex flex-col bg-gray-50 overflow-hidden animate-fade-in">
      <Header modelName={selectedModel} />

      <main className="relative flex-1 flex overflow-hidden">

        {/* --- Left Sidebar (Desktop) / Bottom Sheet (Mobile) --- */}

        {/* Mobile Backdrop */}
        {isMobileMenuOpen && (
          <div 
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-30 md:hidden animate-fade-in"
            onClick={() => setIsMobileMenuOpen(false)}
          />
        )}

        <aside 
          className={`
            fixed inset-x-0 bottom-0 z-40 
            bg-white flex flex-col
            transition-transform duration-500 cubic-bezier(0.32, 0.72, 0, 1)
            shadow-[0_-10px_40px_-15px_rgba(0,0,0,0.3)] rounded-t-3xl h-[85vh]

            md:relative md:inset-auto md:transform-none md:w-[400px] md:h-full md:shadow-xl md:shadow-gray-200/50 md:rounded-none md:border-r md:border-gray-200

            ${isMobileMenuOpen ? 'translate-y-0' : 'translate-y-full md:translate-y-0'}
          `}
        >

          {/* Mobile Handle */}
          <div className="md:hidden w-full flex justify-center pt-3 pb-1 cursor-pointer" onClick={() => setIsMobileMenuOpen(false)}>
             <div className="w-12 h-1.5 bg-gray-300 rounded-full" />
          </div>

          {/* Mode Switcher */}
          <div className="p-4 border-b border-gray-100 flex-shrink-0">
             <div className="flex items-center justify-between mb-4">
               <button 
                  onClick={() => {
                    setSelectedModel(null);
                    setHasApiKey(false);
                    setResultImage(null);
                    setUserImages([]);
                    setRefImages([]);
                  }}
                  className="text-xs font-medium text-gray-400 hover:text-gray-700 flex items-center gap-1 transition-colors"
               >
                  ← Switch Engine
               </button>

               <button 
                 onClick={() => setIsMobileMenuOpen(false)}
                 className="md:hidden text-gray-400 hover:text-gray-700"
               >
                 <X className="w-5 h-5" />
               </button>
             </div>

            <div className="grid grid-cols-2 gap-1 p-1 bg-gray-100/80 rounded-xl">
              <button
                onClick={() => setMode('manga')}
                disabled={isGenerating}
                className={`flex items-center justify-center gap-2 py-2.5 rounded-lg text-sm font-semibold transition-all duration-200
                  ${mode === 'manga' 
                    ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-black/5' 
                    : 'text-gray-500 hover:text-gray-700'
                  }
                `}
              >
                <PenTool className="w-4 h-4" />
                Manga
              </button>
              <button
                onClick={() => setMode('edit')}
                disabled={isGenerating}
                className={`flex items-center justify-center gap-2 py-2.5 rounded-lg text-sm font-semibold transition-all duration-200
                  ${mode === 'edit' 
                    ? 'bg-white text-purple-600 shadow-sm ring-1 ring-black/5' 
                    : 'text-gray-500 hover:text-gray-700'
                  }
                `}
              >
                <Sparkles className="w-4 h-4" />
                Edit
              </button>
            </div>
          </div>

          {/* Scrollable Inputs - Disabled during generation */}
          <div className={`flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8 transition-opacity duration-300 ${isGenerating ? 'opacity-50 pointer-events-none grayscale' : ''}`}>

            {/* Subject Images (Source) */}
            <section className="space-y-4 animate-fade-in" style={{ animationDelay: '0.1s' }}>
              <div className="flex items-center justify-between">
                <div>
                   <div className="flex items-center gap-2">
                    <label className="text-xs font-bold text-gray-900 uppercase tracking-wider">Subject Images</label>
                    <span className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 rounded text-[10px] font-bold">REQUIRED</span>
                   </div>
                   <p className="text-[10px] text-gray-400 mt-0.5">Main characters/content for the manga</p>
                </div>
                <span className="text-[10px] font-medium text-gray-400 bg-gray-100 px-2 py-1 rounded-full">
                  {totalImages} / {currentLimit} Slots Used
                </span>
              </div>

              <div className="space-y-3">
                {/* List existing subjects */}
                {userImages.map((img, idx) => (
                    <ImageUploader 
                      key={`subject-${idx}`}
                      label={`Subject ${idx + 1}`}
                      image={img}
                      onImageChange={(newImg) => handleUpdateUserImage(idx, newImg)}
                      compact
                      className="animate-fade-in"
                    />
                ))}

                {/* Add new subject button */}
                {totalImages < currentLimit && (
                  <ImageUploader 
                    label={userImages.length === 0 ? "Upload Main Subject" : "Add Another Subject"}
                    subLabel={userImages.length === 0 ? "Photo of you, friend, etc." : "Another person/character"}
                    image={null}
                    onImageChange={handleAddUserImage}
                    compact={userImages.length > 0} // Compact for subsequent adds
                    className={userImages.length === 0 ? "" : "border-dashed opacity-80 hover:opacity-100"}
                  />
                )}

                 {/* Empty State Hint */}
                 {userImages.length === 0 && (
                   <div className="flex items-start gap-2 p-3 bg-indigo-50 border border-indigo-100 rounded-lg text-[10px] text-indigo-600">
                      <Users className="w-4 h-4 mt-0.5 flex-shrink-0" />
                      <p>Upload photos of yourself, your friends, or any character you want to appear in the manga panels.</p>
                   </div>
                 )}
              </div>
            </section>

            {/* Reference Images */}
            <section className="space-y-4 animate-fade-in pt-4 border-t border-gray-100" style={{ animationDelay: '0.15s' }}>
              <div>
                <div className="flex items-baseline justify-between mb-1">
                  <label className="text-xs font-bold text-gray-900 uppercase tracking-wider">Style References</label>
                  <span className="text-[10px] text-gray-400">Optional</span>
                </div>
                <p className="text-[10px] text-gray-400 mb-3">Art styles, backgrounds, or mood references</p>

                <div className="space-y-3">
                  {/* List existing references */}
                  {refImages.map((img, idx) => (
                    <ImageUploader 
                      key={`ref-${idx}`}
                      label={`Style Ref ${idx + 1}`}
                      image={img}
                      onImageChange={(newImg) => handleUpdateRefImage(idx, newImg)}
                      compact
                      className="animate-fade-in"
                    />
                  ))}

                  {/* Add new reference button */}
                  {totalImages < currentLimit && (
                    <ImageUploader 
                      label="Add Style Reference"
                      subLabel="Manga page, art style, etc."
                      image={null}
                      onImageChange={handleAddRefImage}
                      compact
                      className="opacity-80 hover:opacity-100"
                    />
                  )}
                </div>
              </div>
            </section>

            {/* Contextual Inputs */}
            <section className="animate-fade-in pt-4 border-t border-gray-100" style={{ animationDelay: '0.2s' }}>
              {mode === 'manga' ? (
                <div className="space-y-6">
                  {/* Style Name */}
                  <div>
                    <label className="text-xs font-bold text-gray-900 uppercase tracking-wider mb-2 block">
                      Art Style
                    </label>
                    <div className="relative group">
                      <input
                        type="text"
                        placeholder="e.g. Cyberpunk, Vintage Shojo, Sketch"
                        value={styleName}
                        onChange={(e) => setStyleName(e.target.value)}
                        className="w-full pl-10 pr-4 py-3 rounded-xl bg-gray-50 border-transparent focus:bg-white focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 transition-all text-sm outline-none"
                      />
                      <Wand2 className="absolute left-3 top-3 w-4 h-4 text-gray-400 group-focus-within:text-indigo-500 transition-colors" />
                    </div>
                  </div>

                  {/* Layout Type */}
                  <div>
                    <label className="text-xs font-bold text-gray-900 uppercase tracking-wider mb-2 block">
                      Layout
                    </label>
                    <div className="grid grid-cols-3 gap-2">
                      {(['single', 'double', 'strip'] as const).map((type) => (
                        <button
                          key={type}
                          onClick={() => setLayoutType(type)}
                          className={`
                            flex flex-col items-center justify-center p-3 rounded-xl border text-[10px] font-bold uppercase tracking-wide transition-all
                            ${layoutType === type 
                              ? 'border-indigo-600 bg-indigo-50 text-indigo-700' 
                              : 'border-gray-200 text-gray-500 hover:bg-gray-50'
                            }
                          `}
                        >
                          <LayoutIcon className="w-4 h-4 mb-1" />
                          {type}
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Dialogue */}
                  <div>
                    <label className="text-xs font-bold text-gray-900 uppercase tracking-wider mb-2 block">
                      Dialogue
                    </label>
                    <div className="relative">
                      <textarea
                        rows={3}
                        placeholder="Add text for speech bubbles..."
                        value={dialogue}
                        onChange={(e) => setDialogue(e.target.value)}
                        className="w-full p-3 rounded-xl bg-gray-50 border-transparent focus:bg-white focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 transition-all text-sm outline-none resize-none"
                      />
                      <MessageSquare className="absolute right-3 bottom-3 w-4 h-4 text-gray-300" />
                    </div>
                  </div>
                </div>
              ) : (
                // Edit Mode Inputs
                <div className="space-y-4">
                  <label className="text-xs font-bold text-gray-900 uppercase tracking-wider mb-2 block">
                    Magic Instructions
                  </label>
                  <textarea
                    rows={6}
                    placeholder="Describe your changes in detail...&#10;e.g. 'Make it look like a oil painting', 'Remove the person on the left', 'Add neon lights'"
                    value={editPrompt}
                    onChange={(e) => setEditPrompt(e.target.value)}
                    className="w-full p-4 rounded-xl bg-purple-50 border-transparent focus:bg-white focus:border-purple-500 focus:ring-2 focus:ring-purple-200 transition-all text-sm outline-none resize-none"
                  />
                </div>
              )}
            </section>
          </div>

          {/* Footer Action */}
          <div className="p-6 border-t border-gray-100 bg-white flex-shrink-0">
            {errorMsg && (
              <div className="mb-4 p-3 rounded-lg bg-red-50 border border-red-100 text-xs text-red-600">
                {errorMsg}
              </div>
            )}
            <button
              onClick={handleGenerate}
              disabled={userImages.length === 0 || isGenerating}
              className={`
                w-full py-4 rounded-xl flex items-center justify-center gap-2 font-bold text-white shadow-lg shadow-indigo-200 transform active:scale-[0.98] transition-all
                ${userImages.length === 0 || isGenerating
                  ? 'bg-gray-300 cursor-not-allowed shadow-none' 
                  : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500'
                }
              `}
            >
              {isGenerating ? (
                <span className="animate-pulse">Generative Process...</span>
              ) : (
                <>
                  <Wand2 className="w-5 h-5" />
                  <span>{mode === 'manga' ? 'Generate Manga' : 'Apply Edits'}</span>
                </>
              )}
            </button>
          </div>
        </aside>

        {/* --- Right Area: Canvas / Preview --- */}
        <section className="flex-1 bg-[#0f172a] relative flex flex-col overflow-hidden">

          {/* Mobile Float Button (Tune) - Only show if not generating and image exists */}
          {!isMobileMenuOpen && !isGenerating && (
             <div className="md:hidden absolute bottom-8 left-1/2 -translate-x-1/2 z-30 animate-fade-in">
                <button 
                  onClick={() => setIsMobileMenuOpen(true)}
                  className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-full shadow-lg shadow-indigo-900/40 active:scale-95 transition-transform hover:bg-indigo-500"
                >
                   <Settings2 className="w-4 h-4" />
                   <span>Tune & Generate</span>
                </button>
             </div>
          )}

          {/* Canvas Toolbar */}
          <div className="absolute top-4 right-4 md:top-6 md:right-6 z-20 flex gap-2">
            {resultImage && (
              <>
                <button 
                  onClick={() => setResultImage(null)}
                  className="p-3 bg-gray-800/80 backdrop-blur-md hover:bg-gray-700 text-white rounded-full shadow-lg transition-all"
                  title="Clear Canvas"
                >
                  <RefreshCw className="w-4 h-4" />
                </button>
                <button 
                  onClick={handleDownload}
                  className="flex items-center gap-2 px-4 py-3 md:px-5 md:py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-full shadow-lg transition-all"
                >
                  <Download className="w-4 h-4" />
                  <span className="hidden md:inline">Download</span>
                </button>
              </>
            )}
          </div>

          {/* The Stage */}
          <div className="flex-1 flex items-center justify-center p-4 md:p-8 overflow-hidden relative">

            {/* Background Grid Pattern */}
            <div className="absolute inset-0 opacity-10 pointer-events-none" 
                 style={{ backgroundImage: 'radial-gradient(#475569 1px, transparent 1px)', backgroundSize: '24px 24px' }}>
            </div>

            {/* Contextual Loading State (Inside Canvas) */}
            <LoadingOverlay isVisible={isGenerating} message={mode === 'manga' ? "Inking Pages..." : "Processing Edits..."} />

            {resultImage ? (
              <div className="relative max-w-full max-h-full animate-scale-in shadow-2xl shadow-black/50">
                <img 
                  src={resultImage} 
                  alt="Generated Art" 
                  className="max-w-full max-h-[calc(100vh-10rem)] object-contain bg-white rounded-sm border-4 md:border-8 border-white"
                />
              </div>
            ) : (
              <div className="text-center max-w-md px-4">
                <div className="w-24 h-24 md:w-32 md:h-32 bg-gray-800/50 rounded-full mx-auto mb-6 md:mb-8 flex items-center justify-center border border-gray-700">
                   <Sparkles className="w-10 h-10 md:w-12 md:h-12 text-gray-600" />
                </div>
                <h2 className="text-2xl md:text-3xl font-bold text-white mb-3 font-display">Ready to Create</h2>
                <p className="text-gray-400 leading-relaxed text-sm md:text-base">
                  Configure your settings {isMobileMenuOpen ? 'below' : 'on the left'} and click generate. 
                  The <strong>{selectedModel === 'gemini-3-pro-image-preview' ? 'Nano Banana Pro' : 'Nano Banana'}</strong> engine will render your artwork here.
                </p>
              </div>
            )}
          </div>
        </section>

      </main>
    </div>
  );
}

export default App;
